<script>
(function(){
  function g(id){return document.getElementById(id);}
  var raw=(g('raw').value||'').replace(/<\/?MORIARTY_CONFIRM>/gi,'').trim();
  var D={}; try{if(raw&&raw[0]==='{')D=JSON.parse(raw);}catch(e){}

  if(D.ui_theme==='light') g('card').classList.add('lt');
  var th=(D.ui_lang==='th');

  if(D.title){ g('pTitle').textContent=D.title; } else { g('pTitle').style.display='none'; }
  g('pName').textContent=(D.name||(th?'ไม่ระบุชื่อ':'Unknown')).toUpperCase();

  g('stampTxt').textContent=th?'ลับ':'CONFIDENTIAL';
  var yr=D.year||''; g('caseNo').textContent='№ MMP-'+(yr||'1879');
  g('footL').textContent=th?'หอจดหมาย L.O.C.':'L.O.C. Archive';
  g('footR').textContent=th?'ผนึกแล้ว':'Sealed';

  var tags=g('pTags');
  function tag(txt,hi){
    if(!txt)return; var d=document.createElement('div');
    d.className='tag'+(hi?' hi':''); d.textContent=txt; tags.appendChild(d);
  }
  tag(D.age?(D.age+(th?' ปี':' yrs')):'', false);
  tag(D.gender, false);
  tag(D.nationality, false);
  tag(D.social_class, true);
  tag(D.occupation, false);

  function kv(wrap, k, v){
    if(!v)return;
    var c=document.createElement('div'); c.className='kv';
    c.innerHTML='<div class="kv-k">'+k+'</div><div class="kv-v">'+v+'</div>';
    wrap.appendChild(c);
  }

  g('tId').textContent=th?'ข้อมูลส่วนตัว':'Personal Dossier';
  var wId=g('bId');
  kv(wId, th?'ชาติกำเนิด / สายเลือด':'Lineage & Background', D.origin);
  kv(wId, th?'รูปลักษณ์และท่าทาง':'Appearance & Bearing', D.appearance);
  kv(wId, th?'เครื่องหมายประจำตัว':'Distinguishing Mark', D.distinguishing_mark);
  kv(wId, th?'อบายมุข / จุดผูกพัน':'Vice / Vice-Virtue', D.vice);
  if(!wId.innerHTML) wId.innerHTML='<div class="empty">'+(th?'ไม่ระบุ':'Not on record')+'</div>';

  g('tStn').textContent=th?'ฐานะและตำแหน่ง':'Standing & Station';
  var wStn=g('bStn');
  kv(wStn, th?'อาชีพ':'Occupation', D.occupation);
  kv(wStn, th?'การศึกษา':'Education', D.education);
  kv(wStn, th?'ถิ่นพำนัก':'Residence', D.residence);
  kv(wStn, th?'ที่พัก':'Housing', D.housing);
  kv(wStn, th?'ชนชั้นทรัพย์':'Wealth', D.wealth);
  if(!wStn.innerHTML) wStn.innerHTML='<div class="empty">'+(th?'ไม่ระบุ':'Not on record')+'</div>';

  if(D.faction||D.reputation||D.yard_attention||D.motive){
    g('sAlg').style.display='block';
    g('tAlg').textContent=th?'ความจงรักภักดีและชื่อเสียง':'Allegiance & Reputation';
    var wAlg=g('bAlg');
    kv(wAlg, th?'ฝ่ายสังกัด':'Faction Alignment', D.faction);
    kv(wAlg, th?'ชื่อเสียงสาธารณะ':'Public Reputation', D.reputation);
    kv(wAlg, th?'ความสนใจของสกอตแลนด์ยาร์ด':'Yard Attention', D.yard_attention);
    kv(wAlg, th?'แรงจูงใจ / บาดแผล':'Motive / Driving Wound', D.motive);
  }

  if(D.public_persona||D.private_agenda){
    g('sMask').style.display='block';
    g('tMask').textContent=th?'หน้ากากและผู้สวม':'The Mask & The Man';
    var wMask=g('bMask');
    function dual(k, v){
      if(!v) return;
      var c=document.createElement('div'); c.className='dual';
      c.innerHTML='<div class="dual-k">'+k+'</div><div class="dual-v">'+v+'</div>';
      wMask.appendChild(c);
    }
    dual(th?'ภาพลักษณ์ต่อสาธารณะ':'Public Persona', D.public_persona);
    dual(th?'วาระซ่อนเร้น':'Private Agenda', D.private_agenda);
  }

  var STATS_EN=[['Intellect','int'],['Cunning','cun'],['Charisma','cha'],['Eloquence','elo'],['Constitution','con'],['Dexterity','dex'],['Resolve','rsv'],['Influence','inf']];
  var STATS_TH=[['สติปัญญา','int'],['เล่ห์เหลี่ยม','cun'],['เสน่ห์','cha'],['วาทศิลป์','elo'],['ร่างกาย','con'],['ความว่องไว','dex'],['จิตใจ','rsv'],['อิทธิพล','inf']];
  g('tSt').textContent=th?'คุณสมบัติ':'Faculties';
  var wSt=g('bSt'); var STATS=th?STATS_TH:STATS_EN;
  var st=D.stats||{};
  STATS.forEach(function(s){
    var v=parseInt(st[s[1]]||5,10); v=Math.max(1,Math.min(10,v));
    var box=document.createElement('div'); box.className='st-card';
    box.innerHTML='<div class="st-lbl">'+s[0]+'</div><div class="st-bar"><div class="st-fill" style="width:'+(v*10)+'%"></div></div><div class="st-v">'+v+'</div>';
    wSt.appendChild(box);
  });

  function rLst(id, secId, tId, title, arr){
    if(arr&&arr.length){
