      var w=g(id);
      arr.forEach(function(i){
        var c=document.createElement('div'); c.className='lst-card';
        c.innerHTML='<div class="lst-n">'+(i.n||'')+'</div><div class="lst-t">'+(i.t||'')+'</div>'+(i.d?('<div class="lst-d">'+i.d+'</div>'):'');
        w.appendChild(c);
      });
    }
  }
  rLst('bSkl','sSkl','tSkl', th?'ศิลปวิทยาที่ร่ำเรียน':'Learnt Arts', D.skills);
  rLst('bRel','sRel','tRel', th?'เครือข่ายแห่งคนรู้จัก':'The Web of Acquaintance', D.relationships);

  if(D.scenario){
    g('sScn').style.display='block';
    g('tScn').textContent=th?'ฉากเปิด':'Opening Scene';
    g('bScn').textContent=D.scenario;
  }
})();
</script>
